import * as React from "react";

export const Guild: React.FunctionComponent = () => {
  return (
    <>
      <p>
        Each Guild is worth a number of victory points depending on the
        configuration of the player’s city and/or that of the two neighboring
        cities (see description of the structures)
      </p>
    </>
  );
};



